import React, { useState, useEffect } from 'react';

export default function ProductForm({ onSaved, editing, setEditing }) {
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [image, setImage] = useState(null);
  const [imagePath, setImagePath] = useState('');
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState(null);

  useEffect(() => {
    if (editing) {
      setName(editing.name || '');
      setPrice(editing.price || '');
      setDescription(editing.description || '');
      setImagePath(editing.imagePath || '');
    }
  }, [editing]);

  function getToken() { return localStorage.getItem('token'); }

  async function uploadFile(file) {
    const fd = new FormData();
    fd.append('image', file);
    const res = await fetch('http://localhost:5000/api/products/upload', {
      method: 'POST',
      headers: { Authorization: 'Bearer ' + getToken() },
      body: fd
    });
    return await res.json();
  }

  async function submit(e) {
    e.preventDefault();
    setLoading(true); setMsg(null);
    try {
      let path = imagePath;
      if (image) {
        const up = await uploadFile(image);
        if (up.error) throw new Error(up.error);
        path = up.path;
      }

      const payload = { name, price: Number(price), description, imagePath: path };
      const token = getToken();
      let res;
      if (editing) {
        res = await fetch(`http://localhost:5000/api/products/${editing._id}`, {
          method: 'PUT', headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + token }, body: JSON.stringify(payload)
        });
      } else {
        res = await fetch('http://localhost:5000/api/products', {
          method: 'POST', headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + token }, body: JSON.stringify(payload)
        });
      }
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Save failed');
      setMsg({ type: 'success', text: 'Saved' });
      setImage(null); setImagePath(''); setName(''); setPrice(''); setDescription('');
      setEditing(null);
      onSaved && onSaved(data);
    } catch (err) {
      setMsg({ type: 'error', text: err.message });
    } finally { setLoading(false); }
  }

  return (
    <form className="product-form" onSubmit={submit}>
      <h4>{editing ? 'Edit Product' : 'Add Product'}</h4>
      {msg && <div className={`alert ${msg.type}`}>{msg.text}</div>}
      <label>Name</label>
      <input value={name} onChange={e => setName(e.target.value)} required />

      <label>Price</label>
      <input value={price} onChange={e => setPrice(e.target.value)} required />

      <label>Description</label>
      <textarea value={description} onChange={e => setDescription(e.target.value)} />

      <label>Image</label>
      <input type="file" onChange={e => setImage(e.target.files[0])} />
      {imagePath && <div className="muted">Current image: <a href={`http://localhost:5000${imagePath}`} target="_blank" rel="noreferrer">view</a></div>}

      <div className="form-actions">
        <button className="btn" type="submit" disabled={loading}>{loading ? 'Saving...' : 'Save'}</button>
        {editing && <button type="button" className="btn ghost" onClick={() => setEditing(null)}>Cancel</button>}
      </div>
    </form>
  );
}
